  await initializer.run();
})();

exports.up = async function up(knex) {
  // See https://github.com/gx0r/connect-session-knex
  // Modeled loosely after https://github.com/gx0r/connect-session-knex/blob/4e0e36a9afbb13c3000a89f5e341f2d2d4339a02/lib/index.js#L114
  // For simplicity we always make the session a string
  // Do NOT change around this table or column names; the connect-session-knex library makes assumptions about them
  await knex.schema.createTable('sessions', table => {
    table.comment('Session data');
    table.string('sid').primary().notNullable().comment('ID of the session');
    table
      .text('sess', 'longtext')
      .notNullable()
      .comment('Session data, JSON serialized');
    table
      .timestamp('expired')
      .notNullable()
      .comment('The point in time when the session expires');
    table.index('sid', 'sessions_sid_idx');
    table.index('expired', 'sessions_expired_idx');
  });
};

mung.headersAsync = function headersAsync(fn) {
  return function(req, res, next) {
    let original = res.end;
    let onError = e => {
      res.end = original;
      return mung.onError(e, req, res, next);
    };
    function headers_async_hook() {
      if (res.headersSent) return original.apply(this, null); // (this, args)
      let args = arguments;
      res.end = () => null;
      try {
        fn(req, res)
          .then(() => {
            res.end = original;
            if (res.headersSent) return;
            original.apply(this, args);
          })
          .catch(e => onError(e));
      } catch (e) {
        onError(e);
      }
    }
    res.end = headers_async_hook;

    next && next();
  };
};

for (const accept of accepts) {
  const act = ContentType.fromString(accept);
  const normalizedCT = act.normalize();
  if (normalizedCT === '*/*') {
    return expectedTypes[0];
  } else if (expectedTypesMap.has(normalizedCT)) {
    return normalizedCT;
  } else if (expectedTypesMap.has(act.mediaType)) {
    return act.mediaType;
  } else if (act.isWildCard) {
    // wildcard of type application/*
    const [type] = normalizedCT.split('/', 1);

    for (const expectedType of expectedTypesMap) {
      if (new RegExp(`^${type}\/.+$`).test(expectedType[0])) {
        return expectedType[1];
      }
    }
  } else {
    for (const expectedType of expectedTypes) {
      const ect = ContentType.fromString(expectedType);
      if (ect.mediaType === act.mediaType) {
        return expectedType;
      }
    }
  }
}

